module freq_div (
    input CLK_in,
    output reg CLK_50,
    output reg CLK_10,
    output reg CLK_1,
    input RST
);

reg [1:0] cnt_50 = 0;
reg [3:0] cnt_10 = 0;
reg [6:0] cnt_100 = 0;

always @(posedge CLK_in or posedge RST) begin
    if (RST) begin
        cnt_50 <= 0;
        cnt_10 <= 0;
        cnt_100 <= 0;
        CLK_50 <= 0;
        CLK_10 <= 0;
        CLK_1 <= 0;
    end else begin
        cnt_50 <= ~cnt_50;
        CLK_50 <= cnt_50[0];

        cnt_10 <= cnt_10 + 1;
        if (cnt_10 == 4'd4) begin
            CLK_10 <= ~CLK_10;
            cnt_10 <= 0;
        end

        cnt_100 <= cnt_100 + 1;
        if (cnt_100 == 7'd49) begin
            CLK_1 <= ~CLK_1;
            cnt_100 <= 0;
        end
    end
end

endmodule
